// server/controllers/product.controller.js
const Product = require('../models/Product');

// @desc    Create a new product listing
// @route   POST /api/products
// @access  Private
const createProduct = async (req, res) => {
  try {
    const { title, description, price, category, condition } = req.body;
    
    // Extract the Cloudinary URLs generated by your existing middleware
    const imageUrls = req.files ? req.files.map(file => file.path) : [];

    const product = await Product.create({
      seller: req.user._id,
      title,
      description,
      price: Number(price),
      category,
      condition,
      images: imageUrls,
      location: {
        district: req.user.location?.district,
        state: req.user.location?.state
      }
    });

    const populatedProduct = await Product.findById(product._id).populate('seller', 'name avatar location contactNumber');
    res.status(201).json(populatedProduct);

  } catch (error) {
    console.error('🔥 ERROR CREATING PRODUCT:', error);
    res.status(500).json({ message: 'Failed to create product listing', error: error.message });
  }
};

// @desc    Get all available products (The Marketplace Feed)
// @route   GET /api/products
// @access  Public or Private
const getProducts = async (req, res) => {
  try {
    // We can add filtering here later (e.g., only show 'Equipment')
    const query = req.query.category ? { category: req.query.category } : {};
    
    const products = await Product.find({ ...query, isAvailable: true })
      .sort({ createdAt: -1 })
      .populate('seller', 'name location');
    
    res.json(products);
  } catch (error) {
    res.status(500).json({ message: 'Server error', error: error.message });
  }
};

// @desc    Delete a product
// @route   DELETE /api/products/:id
// @access  Private
const deleteProduct = async (req, res) => {
  try {
    const product = await Product.findById(req.params.id);
    if (!product) return res.status(404).json({ message: 'Product not found' });

    // Ensure only the seller can delete their own listing
    if (product.seller.toString() !== req.user._id.toString()) {
      return res.status(401).json({ message: 'Not authorized to delete this product' });
    }

    await product.deleteOne();
    res.json({ message: 'Product listing removed' });
  } catch (error) {
    res.status(500).json({ message: 'Server error', error: error.message });
  }
};

module.exports = { createProduct, getProducts, deleteProduct };